var watts = flow.get('m1_pv_watts') || 0;
var dailyKwh = flow.get('m1_daily_kwh') || 0;
var yesterdayKwh = flow.get('m1_yesterday_kwh') || 0;
var nextRisingStr = flow.get('m1_next_rising') || '';
var sunState = flow.get('m1_sun_state') || '';

var now = new Date();
var nowMs = now.getTime();
var hour = now.getHours();

var phase = flow.get('m1_phase') || 'init';
var prevPhase = phase;

// Sunrise - 30 min
var sunrise30Ms = 0;
if (nextRisingStr) {
    sunrise30Ms = new Date(nextRisingStr).getTime() - 30 * 60000;
}

// Skip logic until sun data is available
if (!sunState) {
    return [null, null, null];
}

// --- Phase transitions ---

// 22:00+ -> OFF
if (hour >= 22) {
    phase = 'off';
}
// 21:00-22:00 -> LIFETIME (Lebensleistung)
else if (hour >= 21) {
    phase = 'lifetime';
}
// Night, before sunrise-30min -> OFF
else if (sunState === 'below_horizon' && hour < 12 && sunrise30Ms > 0 && nowMs < sunrise30Ms) {
    phase = 'off';
}
// Sunrise-30min reached, sun not up yet, no production -> MORNING
else if (phase === 'off' || phase === 'init') {
    if (sunState === 'below_horizon' && sunrise30Ms > 0 && nowMs >= sunrise30Ms) {
        phase = 'morning';
    } else if (sunState === 'above_horizon') {
        phase = (watts >= 30) ? 'producing' : 'idle';
    } else if (sunState === 'below_horizon' && hour >= 12) {
        // Restart during evening (after sunset, before 22:00)
        phase = 'idle';
    }
}

// PV >= 50W -> PRODUCING (from morning or idle)
if (watts >= 30 && (phase === 'morning' || phase === 'idle')) {
    phase = 'producing';
}
// PV < 50W after producing -> IDLE
else if (watts < 30 && phase === 'producing') {
    phase = 'idle';
}

// --- Power / Dimmer ---
var powerMsg = null;
var dimmerMsg = null;

if (phase !== prevPhase) {
    if (phase === 'off' && prevPhase !== 'off') {
        powerMsg = {payload: 'OFF'};
    }
    if ((prevPhase === 'off' || prevPhase === 'init') && phase !== 'off') {
        powerMsg = {payload: 'ON'};
        dimmerMsg = {payload: 20};
        flow.set('m1_evening_dimmed', false);
    }
}

// After sunset -> dim to 10 (once)
if (sunState === 'below_horizon' && hour >= 12 && hour < 22 &&
    !flow.get('m1_evening_dimmed') && phase !== 'off') {
    dimmerMsg = {payload: 10};
    flow.set('m1_evening_dimmed', true);
}

// --- Display text ---
var displayText = null;
switch (phase) {
    case 'morning':
        if (yesterdayKwh < 10) {
            displayText = yesterdayKwh.toFixed(1) + 'kW';
        } else if (yesterdayKwh < 100) {
            displayText = yesterdayKwh.toFixed(1) + 'k';
        } else {
            displayText = Math.round(yesterdayKwh) + 'k';
        }
        break;
    case 'producing':
        if (watts < 10000) {
            displayText = Math.round(watts) + 'W';
        } else {
            displayText = Math.round(watts / 1000) + 'kW';
        }
        break;
    case 'idle':
        if (dailyKwh < 10) {
            displayText = dailyKwh.toFixed(1) + 'kW';
        } else if (dailyKwh < 100) {
            displayText = dailyKwh.toFixed(1) + 'k';
        } else {
            displayText = Math.round(dailyKwh) + 'k';
        }
        break;
    case 'lifetime':
        var totalKwh = flow.get('m1_lifetime_kwh') || 0;
        if (totalKwh < 10) {
            displayText = totalKwh.toFixed(1) + 'kW';
        } else if (totalKwh < 1000) {
            displayText = Math.round(totalKwh) + 'kW';
        } else {
            var mwh = totalKwh / 1000;
            if (mwh < 10) {
                displayText = mwh.toFixed(2) + 'M';
            } else if (mwh < 100) {
                displayText = mwh.toFixed(1) + 'M';
            } else {
                displayText = Math.round(mwh) + 'M';
            }
        }
        break;
}

// Dedup
var lastText = flow.get('m1_last_text') || '';
var textMsg = null;
if (displayText && displayText !== lastText) {
    textMsg = {payload: displayText};
    flow.set('m1_last_text', displayText);
}

flow.set('m1_phase', phase);

var fills = {producing:'green', morning:'yellow', idle:'blue', lifetime:'purple'};
node.status({
    fill: fills[phase] || 'grey',
    shape: 'dot',
    text: phase + ': ' + (displayText || 'aus') + ' (' + watts + 'W)'
});

return [textMsg, dimmerMsg, powerMsg];

initialize:
flow.set('m1_phase', 'init');
flow.set('m1_last_text', '');
flow.set('m1_evening_dimmed', false);
flow.set('m1_pv_watts', 0);
flow.set('m1_daily_kwh', 0);
flow.set('m1_yesterday_kwh', 0);
flow.set('m1_lifetime_kwh', 0);

