// Sun state
flow.set('m1_sun_state', msg.payload);

// Extract sunrise/sunset from attributes
var attrs;
if (msg.attributes && msg.attributes.new_state && msg.attributes.new_state.attributes) {
    attrs = msg.attributes.new_state.attributes;
} else if (msg.data && msg.data.new_state && msg.data.new_state.attributes) {
    attrs = msg.data.new_state.attributes;
}

if (attrs) {
    if (attrs.next_rising) {
        flow.set('m1_next_rising', attrs.next_rising);
    }
    if (attrs.next_setting) {
        flow.set('m1_next_setting', attrs.next_setting);
    }
    var sr = attrs.next_rising ? new Date(attrs.next_rising) : null;
    var ss = attrs.next_setting ? new Date(attrs.next_setting) : null;
    var srStr = sr ? String(sr.getHours()).padStart(2,'0') + ':' + String(sr.getMinutes()).padStart(2,'0') : '?';
    var ssStr = ss ? String(ss.getHours()).padStart(2,'0') + ':' + String(ss.getMinutes()).padStart(2,'0') : '?';
    node.status({text: msg.payload + ' | rise:' + srStr + ' set:' + ssStr});
}
